import { test, expect } from '@playwright/test';

test('Amazon.sg Magic Tree House Boxed Set price validation and add to cart', async ({ page }) => {
  // 1. Launch browser.
  // 2. Navigate to https://www.amazon.sg.
  await page.goto('https://www.amazon.sg');

  // 3. Wait for input[name="field-keywords"] to be visible.
  const searchInput = page.locator('input[name="field-keywords"]');
  await expect(searchInput).toBeVisible();

  // 4. Fill input[name="field-keywords"] with "Magic Tree House Boxed Set".
  await searchInput.fill('Magic Tree House Boxed Set');

  // 5. Press Enter key in input[name="field-keywords"] to submit the search.
  await searchInput.press('Enter');

  // 6. Wait for search results to load and for the first product link to be visible.
  const firstProductLink = page.locator('.s-search-results .s-result-item h2 a').first();
  await expect(firstProductLink).toBeVisible();

  // 7. Click on the first product link in the search results.
  await firstProductLink.click();

  // 8. Wait for the product detail page to load and for the product title to be visible.
  const productTitle = page.locator('#productTitle');
  await expect(productTitle).toBeVisible();

  // 9. Read the text content of the product title element.
  const titleText = await productTitle.textContent();

  // 10. Read the text content of the product price element.
  let priceText = '';
  const ourPrice = page.locator('#priceblock_ourprice');
  const dealPrice = page.locator('#priceblock_dealprice');
  const offscreenPrice = page.locator('.a-price .a-offscreen').first();

  if (await ourPrice.isVisible()) {
    priceText = await ourPrice.textContent();
  } else if (await dealPrice.isVisible()) {
    priceText = await dealPrice.textContent();
  } else if (await offscreenPrice.isVisible()) {
    priceText = await offscreenPrice.textContent();
  } else {
    throw new Error('Price element not found');
  }

  // 11. Parse the price value as a number.
  const priceMatch = priceText?.replace(/[^0-9.,]/g, '').match(/[\d.,]+/);
  if (!priceMatch) throw new Error('Price value not found');
  const priceValue = parseFloat(priceMatch[0].replace(',', ''));

  // 12. Validate that the price value is less than 25.
  expect(priceValue).toBeLessThan(25);

  // 13. If validation passes, click the "Add to Cart" button.
  const addToCartButton = page.locator('#add-to-cart-button');
  await expect(addToCartButton).toBeVisible();
  await addToCartButton.click();

  // 14. Wait for either a cart confirmation message OR for the cart count element to update and increase by 1.
  const cartCount = page.locator('#nav-cart-count');
  const initialCartCount = parseInt(await cartCount.textContent() || '0', 10);

  const confirmation = page.locator('#huc-v2-order-row-confirm-text');
  await Promise.race([
    confirmation.waitFor({ state: 'visible', timeout: 10000 }),
    cartCount.waitFor({ state: 'visible', timeout: 10000 }).then(async () => {
      // Wait for cart count to increase
      await expect(cartCount).toHaveText((count) => parseInt(count, 10) > initialCartCount);
    })
  ]);

  // 15. Close the browser.
  // (Playwright test runner handles browser closure automatically)
});
